package com.love.cinemaplayer;import android.app.Activity;import android.net.Uri;import android.os.Bundle;import android.view.View;import android.widget.TextView;import android.widget.VideoView;import org.eclipse.paho.client.mqttv3.IMqttActionListener;import org.eclipse.paho.client.mqttv3.IMqttDeliveryToken;import org.eclipse.paho.client.mqttv3.IMqttToken;import org.eclipse.paho.client.mqttv3.MqttAsyncClient;import org.eclipse.paho.client.mqttv3.MqttCallbackExtended;import org.eclipse.paho.client.mqttv3.MqttClient;import org.eclipse.paho.client.mqttv3.MqttConnectOptions;import org.eclipse.paho.client.mqttv3.MqttMessage;import org.json.JSONObject;public class MainActivity extends Activity {    private VideoView videoPlayer;    private TextView infoLabel;    private MqttAsyncClient client;    @Override    protected void onCreate(Bundle savedInstanceState) {        super.onCreate(savedInstanceState);        setContentView(android.R.id.content);                videoPlayer = new VideoView(this);        infoLabel = new TextView(this);        infoLabel.setText("🎬 WAITING FOR HOST SIGNAL...");        infoLabel.setTextSize(20);        infoLabel.setTextColor(0xFF89B4FA);                android.widget.RelativeLayout layout = new android.widget.RelativeLayout(this);        layout.setBackgroundColor(0xFF11111B);                android.widget.RelativeLayout.LayoutParams params = new android.widget.RelativeLayout.LayoutParams(            android.widget.RelativeLayout.LayoutParams.WRAP_CONTENT, android.widget.RelativeLayout.LayoutParams.WRAP_CONTENT);        params.addRule(android.widget.RelativeLayout.CENTER_IN_PARENT);        layout.addView(infoLabel, params);        layout.addView(videoPlayer, new android.widget.RelativeLayout.LayoutParams(            android.widget.RelativeLayout.LayoutParams.MATCH_PARENT, android.widget.RelativeLayout.LayoutParams.MATCH_PARENT));        videoPlayer.setVisibility(View.GONE);                setContentView(layout);        startMqtt();    }    private void startMqtt() {        try {            String clientId = MqttClient.generateClientId();            client = new MqttAsyncClient("tcp://broker.emqx.io:1883", clientId, null);            MqttConnectOptions options = new MqttConnectOptions();            options.setAutomaticReconnect(true);            options.setCleanSession(true);            client.connect(options, null, new IMqttActionListener() {                @Override public void onSuccess(IMqttToken token) { try { client.subscribe("my_cinema/love_cinema_room_secret_999/control", 1); } catch (Exception e) {} }                @Override public void onFailure(IMqttToken asyncActionToken, Throwable exception) {}            });            client.setCallback(new MqttCallbackExtended() {                @Override public void connectComplete(boolean reconnect, String serverURI) {}                @Override public void connectionLost(Throwable cause) {}                @Override public void deliveryComplete(IMqttDeliveryToken token) {}                @Override                public void messageArrived(String topic, MqttMessage message) throws Exception {                    JSONObject data = new JSONObject(new String(message.getPayload()));                    final String action = data.getString("action");                    final String url = data.optString("url", "");                    runOnUiThread(() -> {                        if (action.equals("load") && !url.isEmpty()) {                            infoLabel.setVisibility(View.GONE);                            videoPlayer.setVisibility(View.VISIBLE);                            videoPlayer.setVideoURI(Uri.parse(url));                            videoPlayer.start();                        } else if (action.equals("play")) { videoPlayer.start(); }                        else if (action.equals("pause")) { videoPlayer.pause(); }                    });                }            });        } catch (Exception e) {}    }}